 38	int get_lds_size() {
 39	  static bool is_cached = false;
 40	  static int result;
 41	  if (is_cached == false) {
 42	    auto dprops = at::cuda::getCurrentDeviceProperties();
 43	    std::string device_arch = dprops->gcnArchName;
 44	    size_t substring = device_arch.find("gfx95");
 45	    result = (substring == std::string::npos ? 64 * 1024 : 160 * 1024);
 46	    is_cached = true;
 47	  }
 48	  return result;
 49	}
