132	__device__ __forceinline__ float4 load_ntmprl(const float4* addr) {
133	  auto addr_alias = reinterpret_cast<const float*>(addr);
134	  auto dat0 = loadnt(addr_alias);
135	  auto dat1 = loadnt(addr_alias + 1);
136	  auto dat2 = loadnt(addr_alias + 2);
137	  auto dat3 = loadnt(addr_alias + 3);
138	  return make_float4(dat0, dat1, dat2, dat3);
139	}
