141	// TBlock fetches entire rows of A, and entire col of B (K dimension); assume
142	// N=1 for time being grid is M/A_NUM_ROWS blocks
143	template <typename scalar_t, int NUM_A_ROWS_PER_BLOCK>
144	__global__ void LLGemm1_kernel(const scalar_t* in_a, const scalar_t* in_b,
145	                               scalar_t* out_c, const int K) {
146	  using scalar2_t = typename scalar2<scalar_t>::type;
147	  auto af4 = reinterpret_cast<const float4*>(in_a);
148	  auto bf4 = reinterpret_cast<const scalar2_t*>(in_b);
149	  auto c = reinterpret_cast<scalar2_t*>(out_c);
150	  __shared__ float red_smem[NUM_A_ROWS_PER_BLOCK][WARP_SIZE];
151	  const int row_addr = blockIdx.x * NUM_A_ROWS_PER_BLOCK * K / 8;
152	  const int threadid = threadIdx.x;
153	  const int warp = threadIdx.x / WARP_SIZE;
154	  const int lane = threadIdx.x % WARP_SIZE;
155	  const int num_warps = blockDim.x / WARP_SIZE;
156	  const int qwarpid = threadid / 16;
157	  const int qthreadid = threadid % 16;
158	  float4 rowA_elem4[NUM_A_ROWS_PER_BLOCK];
159	  scalar2_t colB_elem4x, colB_elem4y, colB_elem4z, colB_elem4w;
160	  float acc[NUM_A_ROWS_PER_BLOCK];
161	  scalar2_t acch2;
162	  scalar2_t oval;
163	
164	  // As we later use warp shuffle operations, we may have more threads in the
165	  // block than the actual available data, hence the if guard here.
166	  if (threadid * 8 < K) {
167	#pragma unroll
168	    for (int i = 0; i < NUM_A_ROWS_PER_BLOCK; i++) {
169	      // rowA_elem4[i] holds 8 * half numbers seen as a single float4.
170	      rowA_elem4[i] = load_ntmprl(&af4[row_addr + threadid + K / 8 * i]);
171	    }
172	    colB_elem4x = bf4[threadid * 4 + 0];
173	    colB_elem4y = bf4[threadid * 4 + 1];
174	    colB_elem4z = bf4[threadid * 4 + 2];
175	    colB_elem4w = bf4[threadid * 4 + 3];
176	  }
177	
178	  scalar2_t Af2;
179	  float2 S;
180	
181	  auto Ah2ptr = reinterpret_cast<scalar2_t*>(&rowA_elem4);
182	  scalar2_t* ah2lptr;
183	
184	#pragma unroll
185	  for (int i = 0; i < NUM_A_ROWS_PER_BLOCK; i++) {
186	    // Multiply-add on 8 scalar_t.
187	    ah2lptr = Ah2ptr + i * 4;
188	    Af2 = *(ah2lptr);
189	    acch2 = __hmul2(Af2, colB_elem4x);
190	    Af2 = *(ah2lptr + 1);
191	    acch2 = __hfma2(Af2, colB_elem4y, acch2);
192	    Af2 = *(ah2lptr + 2);
193	    acch2 = __hfma2(Af2, colB_elem4z, acch2);
194	    Af2 = *(ah2lptr + 3);
195	    acch2 = __hfma2(Af2, colB_elem4w, acch2);
196	    S = __s22float2(acch2);
197	
198	    // See comment above concerning the if guard.
199	    acc[i] = (threadid * 8 < K ? S.x + S.y : 0.f);
200	  }

200	  }
201	
202	// all reduce across warp.
203	#pragma unroll
204	  for (int mask = WARP_SIZE / 2; mask >= 1; mask /= 2) {
205	#pragma unroll
206	    for (int i = 0; i < NUM_A_ROWS_PER_BLOCK; i++) {
207	      acc[i] += __shfl_xor(acc[i], mask);
208	    }
209	  }
210	
211	  // Warp leaders store the data to shared memory.
212	  if (lane < NUM_A_ROWS_PER_BLOCK) {
213	    red_smem[lane][warp] = acc[lane];
214	  }
215	
216	  // Make sure the data is in shared memory.
217	  __syncthreads();
218	
219	  if (qwarpid < NUM_A_ROWS_PER_BLOCK) {
220	    acc[qwarpid] = qthreadid < num_warps ? red_smem[qwarpid][qthreadid] : 0.f;
221	#pragma unroll
222	    for (int mask = 16 / 2; mask >= 1; mask /= 2) {
223	      acc[qwarpid] += __shfl_xor(acc[qwarpid], mask);
224	    }
225	    float oval2 = __shfl_xor(acc[qwarpid], 16);
226	
227	    if (lane % 32 == 0) {
228	      oval = __float22s2_rn<scalar2_t>(make_float2(acc[qwarpid], oval2));
229	      c[blockIdx.x * NUM_A_ROWS_PER_BLOCK / 2 + qwarpid / 2] = oval;
230	    }
231	  }
232	}
