234	torch::Tensor LLMM1(at::Tensor& in_a, at::Tensor& in_b,
235	                    const int64_t rows_per_block) {
236	  auto M = in_a.size(0);
237	  auto K = in_a.size(1);
238	  auto N = in_b.size(0);
239	
240	  TORCH_CHECK(N == 1, "Row number of activation tensor must be 1.");
241	  TORCH_CHECK(in_a.dtype() == in_b.dtype());
242	  TORCH_CHECK(in_b.dtype() == torch::kFloat16 ||
243	              in_b.dtype() == torch::kBFloat16);
244	
245	  auto out_c = torch::empty(
246	      {N, M}, torch::TensorOptions().dtype(in_b.dtype()).device(in_b.device()));
247	
248	  // NUM_TREADS need to be a multiple of WARP_SIZE, as we are using warp shuffle
249	  // operations.
250	  const int NUM_THREADS =
251	      max(rows_per_block * 16,
252	          K * 2 / 16 % WARP_SIZE == 0
253	              ? K * 2 / 16
254	              : K * 2 / 16 + (WARP_SIZE - K * 2 / 16 % WARP_SIZE));
255	
256	  int NUM_BLOCKS = M / rows_per_block;
257	
258	  const at::cuda::OptionalCUDAGuard device_guard(device_of(in_b));
259	  const cudaStream_t stream = at::cuda::getCurrentCUDAStream();
260	
261	  // call the kernel function...
262	  AT_DISPATCH_REDUCED_FLOATING_TYPES(in_b.scalar_type(), "LLGemm1", [&] {
263	    auto a_ptr = in_a.data_ptr<scalar_t>();
264	    auto b_ptr = in_b.data_ptr<scalar_t>();
265	    auto c_ptr = out_c.data_ptr<scalar_t>();
266	    if (rows_per_block == 2) {
267	      LLGemm1_kernel<scalar_t, 2>
268	          <<<NUM_BLOCKS, NUM_THREADS, 0, stream>>>(a_ptr, b_ptr, c_ptr, K);
269	    } else if (rows_per_block == 4) {
270	      LLGemm1_kernel<scalar_t, 4>
271	          <<<NUM_BLOCKS, NUM_THREADS, 0, stream>>>(a_ptr, b_ptr, c_ptr, K);
272	    } else if (rows_per_block == 8) {
273	      LLGemm1_kernel<scalar_t, 8>
274	          <<<NUM_BLOCKS, NUM_THREADS, 0, stream>>>(a_ptr, b_ptr, c_ptr, K);
275	    } else if (rows_per_block == 16) {
276	      LLGemm1_kernel<scalar_t, 16>
277	          <<<NUM_BLOCKS, NUM_THREADS, 0, stream>>>(a_ptr, b_ptr, c_ptr, K);
278	    } else {
279	      NUM_BLOCKS = M / 4;
280	      LLGemm1_kernel<scalar_t, 4>
281	          <<<NUM_BLOCKS, NUM_THREADS, 0, stream>>>(a_ptr, b_ptr, c_ptr, K);
282	    }
283	  });
284	
285	  return out_c;
286	}
