288	#define DOT2C(V0, V2, V3)                                                     \
289	  if constexpr (std::is_same_v<scalar_t, half>) {                             \
290	    asm("v_dot2c_f32_f16 %0, %2, %3" : "=v"(V0) : "0"(V0), "v"(V2), "v"(V3)); \
291	  } else if constexpr (std::is_same_v<scalar_t, __hip_bfloat16>) {            \
292	    float2 s = __bfloat1622float2(*((__hip_bfloat162*)(&(V2)))) *             \
293	               __bfloat1622float2(*((__hip_bfloat162*)(&(V3))));              \
294	    V0 += (s.x + s.y);                                                        \
295	  }
