302	#if defined(__HIP__GFX9__)  // TODO: Add NAVI support
303	// This version targets cases where A[] fits LDS capacity
304	template <typename scalar_t, int THRDS, int YTILE, int WvPrGrp, int A_CHUNK,
305	          int UNRL, int N>
306	__global__ void __launch_bounds__(WvPrGrp* THRDS)
307	    wvSplitK_hf_sml_(const int K, const int M, const int Bx, const int By,
308	                     const scalar_t* B, const scalar_t* __restrict__ A,
309	                     const scalar_t* __restrict__ BIAS, scalar_t* C,
310	                     const int _WvPrGrp, const int CuCount) {
311	  constexpr int max_lds_len = LDS_SIZE / 2;
312	  #if defined(__HIP__MI3XX__)
313	  constexpr bool use_mfma = (std::is_same_v<scalar_t, __hip_bfloat16>);
314	  #else
315	  constexpr bool use_mfma = false;
316	  #endif
317	
318	  using scalar8 =
319	      __attribute__((__vector_size__((A_CHUNK / 2) * sizeof(float)))) float;
320	  using half4 =
321	      __attribute__((__vector_size__((A_CHUNK / 2) * sizeof(__bf16)))) __bf16;
322	  union bigType {
323	    scalar_t h[A_CHUNK];
324	    float f[A_CHUNK / 2];
325	    float2 f2[A_CHUNK / 4];
326	    double d[A_CHUNK / 4];
327	    half4 h4[A_CHUNK / 4];
328	    scalar8 h8;
329	  };
330	
331	  //----------------------------------------------------
332	  // Reserving 64/160 KB of LDS to have 1 WG / CU
333	  // Goal is to bring the activation matrix A to the LDS
334	  // and use it across the lifetime of the work group
335	  // TODO: When activation matrix is larger than 64 KB
336	  //	     then this is not going to work!
337	  //----------------------------------------------------
338	  __shared__ scalar_t s[max_lds_len];
339	
340	  //----------------------------------------------------
341	  // Fetch the activation matrix to LDS
342	  // Loop iteration:
343	  // - Each thread (lane) is fetching 8 elements (A_Chunk)
344	  // - Each wave will fetch 64*8=> 512 elements
345	  // - Each WG will fetch 512 * 16 => 8K elements
346	  // - Then the WG will move to another 8 K elements
347	  // TODO: Logic below will only work when K is multiple of 8
348	  //----------------------------------------------------
349	  for (uint32_t k = 0; k < min__(K * N, max_lds_len);
350	       k += THRDS * WvPrGrp * A_CHUNK) {
351	    uint32_t k_in = k + ((threadIdx.y * THRDS + threadIdx.x) * A_CHUNK);
352	
353	    if (k_in >= min__(K * N, max_lds_len)) break;
354	
355	    *((bigType*)(&s[k_in])) = *((bigType*)(&A[k_in]));
356	  }
357	  __syncthreads();
358	
359	  if (threadIdx.y >= _WvPrGrp) return;
360	
361	  uint32_t m = (blockIdx.x * _WvPrGrp + (threadIdx.y % _WvPrGrp)) * YTILE;
362	
363	  float sum[N][YTILE];
364	  scalar8 sum4[N][YTILE];
365	
366	  //----------------------------------------------------
367	  // Each wave works on a single column of weight matrix.
368	  // There are 16 waves per WG, and hence, each WG is
369	  // working on 16 columns of weight matrix. Moreover,
370	  // we tile in column direction by YTILE, so when YTILE=1
371	  // the above math is right, however, when YTILE=2 then
372	  // each wave  will be working on 2 columns and WG will
373	  // be working on 32 columns.
374	  //
375	  // Top level loop that makes WGs persistent!
376	  // - WGs iterates across columns of weight matrix
377	  // - Each wave within WG works on a given column(s)
378	  // - After completing first set of columns, WGs start
379	  //   working on the next set of available columns
380	  //----------------------------------------------------
381	  while (m < M) {
382	    //----------------------------------------------------
383	    // 'sum' accumulates the matrix A x B computation
384	    // split across 64 lanes.
385	    //
386	    // YTILE represents how many column of weight matrix
387	    // are being worked on by each wave.
388	    //----------------------------------------------------
389	    for (int i = 0; i < YTILE; i++)
390	      for (int n = 0; n < N; n++)
391	        if constexpr (!use_mfma)
392	          sum[n][i] = 0;
393	        else
394	          sum4[n][i] = {0, 0, 0, 0};
395	
396	    bigType bigA[N][UNRL];
397	    bigType bigB[YTILE][UNRL];
398	    //----------------------------------------------------
399	    // Fetch weight matrix B in interleaved K-split!
400	    // - Each thread (lane) is fetching 8 elements (A_Chunk)
401	    // - Each wave will fetch 64*8=> 512 elements (1024B)
402	    // - YTILE represents the number of column being serviced
403	    //   by wave
404	    // - Loop for fetching weight matrix (B) are unrolled
405	    //
406	    // Fetch activation matrix A from LDS
407	    // - Loop for fetching activation matrix (A) are unrolled
408	    //
409	    // Finally, do the matrix multiplication in an unrolled
410	    // fashion. This provides lot of food for compiler
411	    // scheduling.
412	    //
413	    // TODO: Logic below will only work when K is multiple of 8
414	    //----------------------------------------------------
415	    // for (uint32_t k1 = 0; k1 < K; k1 += THRDS * A_CHUNK * UNRL) {
416	    for (uint32_t k1 = 0; k1 < K; k1 += THRDS * A_CHUNK * UNRL) {
417	      // Fetch the weight matrix from memory!
418	  #pragma unroll
419	      for (uint32_t k2 = 0; k2 < UNRL; k2++) {
420	        uint32_t k = k1 + k2 * THRDS * A_CHUNK;
421	        uint32_t k_ = k + threadIdx.x * A_CHUNK;
422	        if (k_ >= K) break;
423	
424	        const scalar_t* B_ = &B[(m + 0) * K + k_];
425	        for (int y = 0; y < YTILE; y++)
426	          bigB[y][k2].h8 = (loadnt((scalar8*)(&B_[y * K])));
427	      }
428	
429	      // Fetch activation matrix from either just LDS or from both LDS / memory
430	  #pragma unroll
431	      for (uint32_t k2 = 0; k2 < UNRL; k2++) {
432	        uint32_t k = k1 + k2 * THRDS * A_CHUNK;
433	        uint32_t k_ = k + threadIdx.x * A_CHUNK;
434	        if (k_ >= K) break;
435	
436	        // Fetch A activation matrix in interleaved fashion from LDS or memory
437	
438	        for (int n = 0; n < N; n++) {
439	          bigA[n][k2] = *((const bigType*)(&(s[k_ + K * n])));
440	        }
441	      }
442	
443	      // Do the matrix multiplication in interleaved manner
444	  #pragma unroll
445	      for (uint32_t k2 = 0; k2 < UNRL; k2++) {
446	        uint32_t k = k1 + k2 * THRDS * A_CHUNK;
447	        uint32_t k_ = k + threadIdx.x * A_CHUNK;
448	        if (k_ >= K) break;
449	        // Do the matrix multiplication of activation and weight matrix
450	        // - Remember the accumulation is happening for K-split of 64!
451	  #pragma unroll
452	        for (uint32_t n = 0; n < N; n++) {
453	  #pragma unroll
454	          for (int y = 0; y < YTILE; y++) {
455	            if constexpr (!use_mfma)
456	  #pragma unroll
457	              for (uint32_t b = 0; b < A_CHUNK / 2; b++) {
458	                DOT2C(sum[n][y], bigA[n][k2].f[b], bigB[y][k2].f[b])
459	              }
460	            else
461	  #pragma unroll
462	              for (uint32_t b = 0; b < A_CHUNK / 4; b++)
463	                sum4[n][y] = __builtin_amdgcn_mfma_f32_4x4x4bf16_1k(
464	                    bigA[n][k2].h4[b], bigB[y][k2].h4[b], sum4[n][y], 0, 0, 0);
465	          }
466	        }
467	      }
468	    }
469	
470	    //----------------------------------------------------
471	    // Final reduction step using shuffle
472	    //----------------------------------------------------
473	    if constexpr (!use_mfma) {
474	      for (int n = 0; n < N; n++) {
475	        for (int y = 0; y < YTILE; y++) {
476	          asm("s_nop 0\n\tv_add_f32 %0, %2, %3 row_shr:8 bound_ctrl:0 "
477	              : "=v"(sum[n][y])
478	              : "0"(sum[n][y]), "v"(sum[n][y]), "v"(sum[n][y]));
479	          asm("s_nop 0\n\tv_add_f32 %0, %2, %3 row_shr:4 bound_ctrl:0 "
480	              : "=v"(sum[n][y])
481	              : "0"(sum[n][y]), "v"(sum[n][y]), "v"(sum[n][y]));
482	          asm("s_nop 0\n\tv_add_f32 %0, %2, %3 row_shr:2 bound_ctrl:0 "
483	              : "=v"(sum[n][y])
484	              : "0"(sum[n][y]), "v"(sum[n][y]), "v"(sum[n][y]));
485	          asm("s_nop 0\n\tv_add_f32 %0, %2, %3 wave_shr:1 bound_ctrl:0"
486	              : "=v"(sum[n][y])
487	              : "0"(sum[n][y]), "v"(sum[n][y]), "v"(sum[n][y]));
488	          asm("s_nop 0\n\tv_add_f32 %0, %2, %3 row_bcast:15 bound_ctrl:0"
489	              : "=v"(sum[n][y])
490	              : "0"(sum[n][y]), "v"(sum[n][y]), "v"(sum[n][y]));
491	          asm("s_nop 0\n\tv_add_f32 %0, %2, %3 row_bcast:31 bound_ctrl:0"
492	              : "=v"(sum[n][y])
493	              : "0"(sum[n][y]), "v"(sum[n][y]), "v"(sum[n][y]));
494	        }
495	      }
496	
497	      if (threadIdx.x == 63) {
498	        for (int n = 0; n < N; n++) {
499	          for (int i = 0; i < YTILE; i++) {
500	            if constexpr (std::is_same_v<scalar_t, half>) {
501	              if (BIAS)
502	                sum[n][i] += __half2float(BIAS[(m + i) % Bx + (n % By) * M]);
503	            } else if constexpr (std::is_same_v<scalar_t, __hip_bfloat16>) {
504	              if (BIAS)
505	                sum[n][i] +=
506	                    __bfloat162float(BIAS[(m + i) % Bx + (n % By) * M]);
507	            }
508	            C[m + i + n * M] = __float2s<scalar_t>(sum[n][i]);
509	          }
510	        }
511	      }
512	    } else {
513	  #pragma unroll
514	      for (int n = 0; n < N; n++) {
515	  #pragma unroll
516	        for (int y = 0; y < YTILE; y++) {
517	          // float accm1 = 0;
518	          // for (int i=0; i<64; i++)
