1256	// Find the min val of div2 that doesn't increase N/(div1*div2)
1257	int mindiv(int N, int div1, int div2) {
1258	  int nPrRnd = div1 * div2;
1259	  int rnds[13];
1260	  for (int i = 0; i < 13; i++) {
1261	    rnds[i] = (N + nPrRnd - 1) / nPrRnd;
1262	    nPrRnd -= div1;
1263	  }
1264	  for (int i = 12; i >= 0; i--)
1265	    if (rnds[0] == rnds[i]) return (div2 - i);
1266	  return 0;
1267	}
